class TaskPublisher(RabbitMQClient):
    def publish_task(self, task_name: str, payload: Optional[Dict[str, Any]] = None) -> str:
        self.ensure_connected()
        task_id = str(uuid.uuid4())
        message = {
            "task_id": task_id,
            "task_name": task_name,
            "payload": payload or {},
            "created_at": time.time(),
        }
        body = json.dumps(message)
        self.channel.basic_publish(
            exchange="",
            routing_key=self.config.queue_name,
            body=body,
            properties=pika.BasicProperties(
                delivery_mode=2,
                content_type="application/json",
            ),
        )
        logger.info("Published task: %s", message)
        return task_id


class TaskConsumer(RabbitMQClient):
    def __init__(self, config: RabbitMQConfig):
        super().__init__(config)
        self._stop_event = threading.Event()

    def process_task(self, task: Dict[str, Any]) -> None:
        task_id = task.get("task_id")
        task_name = task.get("task_name")
        payload = task.get("payload", {})
        logger.info("Processing task_id=%s task_name=%s payload=%s", task_id, task_name, payload)
        duration = payload.get("duration", 1)
        try:
            duration = float(duration)
        except Exception:
            duration = 1
        time.sleep(max(duration, 0))
        logger.info("Completed task_id=%s", task_id)

    def _callback(self, ch, method, properties, body) -> None:
        try:
            task = json.loads(body.decode("utf-8"))
            self.process_task(task)
            ch.basic_ack(delivery_tag=method.delivery_tag)
        except Exception as e:
            logger.exception("Failed to process message: %s", e)
            ch.basic_nack(delivery_tag=method.delivery_tag, requeue=True)

    def start_consuming(self) -> None:
        self.ensure_connected()
        self.channel.basic_qos(prefetch_count=self.config.prefetch_count)
        self.channel.basic_consume(
            queue=self.config.queue_name,
            on_message_callback=self._callback,
        )
        logger.info("Waiting for messages on queue=%s", self.config.queue_name)
        try:
            self.channel.start_consuming()
        except KeyboardInterrupt:
            self.stop()
        except Exception as e:
            logger.exception("Consumer error: %s", e)
            raise

    def stop(self) -> None:
        self._stop_event.set()
        try:
            if self.channel and self.channel.is_open:
                self.channel.stop_consuming()
        except Exception as e:
            logger.warning("Error stopping consumer: %s", e)
        self.close()


def run_publisher(args) -> None:
    config = RabbitMQConfig(
        host="localhost",
        port=5672,
        queue_name=args.queue,
        durable=True,
    )
    publisher = TaskPublisher(config)
    try:
        publisher.connect()
        payload = {"duration": args.duration}
        if args.payload:
            try:
                payload.update(json.loads(args.payload))
            except json.JSONDecodeError:
                logger.warning("Invalid JSON payload provided, using duration only")
        task_id = publisher.publish_task(task_name=args.task_name, payload=payload)
        print(task_id)
    finally:
        publisher.close()


def run_consumer(args) -> None:
    config = RabbitMQConfig(
        host="localhost",
        port=5672,
        queue_name=args.queue,
        durable=True,
        prefetch_count=args.prefetch,
    )
    consumer = TaskConsumer(config)

    def handle_signal(signum, frame):
        logger.info("Received signal %s, shutting down", signum)
        consumer.stop()
        sys.exit(0)

    signal.signal(signal.SIGINT, handle_signal)
    signal.signal(signal.SIGTERM, handle_signal)

    try:
        consumer.connect()
        consumer.start_consuming()
    finally:
        consumer.close()


def build_parser() -> argparse.ArgumentParser:
    parser = argparse.ArgumentParser(description="RabbitMQ task publisher and consumer")
    subparsers = parser.add_subparsers(dest="command", required=True)

    pub_parser = subparsers.add_parser("publish", help="Publish a task message")
